/**
 * @param {unknown} item
 * @returns { item is Record<keyof any, unknown> }
 */
const isObject = (item) => {
  if (typeof item !== 'object' || item === null) {
    return false;
  }

  const prototype = Object.getPrototypeOf(item);
  return (
    (prototype === null
      || prototype === Object.prototype
      || Object.getPrototypeOf(prototype) === null)
    && !(Symbol.toStringTag in item)
    && !(Symbol.iterator in item)
  );
};

/**
 * @param {unknown} source
 */
const cloneDeep = (source) => {
  if (!isObject(source)) {
    return source;
  }

  /** @type {Record<keyof any, unknown>} */
  const output = {};

  Object.keys(source).forEach((key) => {
    output[key] = cloneDeep(source[key]);
  });

  return output;
};

/**
 * @typedef {Object} MergeOptions
 * @prop {boolean} [clone]
 * @prop {boolean} [allowOnlySourceKeys]
 */

/**
 * @param {Record<string, any>} target
 * @param {Record<string, any>} source
 * @param {MergeOptions} [options]
 */
export const mergeDeep = (
  target,
  source,
  options = { clone: true, allowOnlySourceKeys: false },
) => {
  const { clone = true, allowOnlySourceKeys = false } = options;
  const output = clone ? { ...target } : target;

  if (isObject(target) && isObject(source)) {
    if (allowOnlySourceKeys) {
      Object.keys(output).forEach((key) => {
        if (!(key in source)) {
          delete output[key];
        }
      });
    }
    Object.keys(source).forEach((key) => {
      if (key === '__proto__') {
        return;
      }

      if (isObject(source[key]) && key in target && isObject(target[key])) {
        // @ts-ignore
        output[key] = mergeDeep(target[key], source[key], options);
      } else if (clone) {
        output[key] = isObject(source[key])
          ? cloneDeep(source[key])
          : source[key];
      } else {
        output[key] = source[key];
      }
    });
  }

  return output;
};

/** @param {string} str */
export const camelCaseToKebabCase = (str) => (typeof str === 'string'
  ? str.replace(/[A-Z]/g, (x) => `-${x.toLowerCase()}`)
  : '');

/**
 * @param {string} prop
 * @param {string} value
 */
export const toCssValue = (prop, value) =>
  `${camelCaseToKebabCase(prop)}: ${value};`;

/**
 * @param {Record<string, any>} target
 * @param {Record<string, any>} source
 */
export const diffDeep = (target = {}, source = {}) => {
  const keysInTargetAndSource = /** @type {Record<string, any>} */ ({});
  const keysOnlyInTarget = /** @type {Record<string, any>} */ ({});

  /**
   * @param {Record<string, any>} targetObj
   * @param {Record<string, any>} sourceObj
   * @param {Record<string, any>} keysInBothAcc
   * @param {Record<string, any>} keysInTargetAcc
   */
  const findCommonKeys = (
    targetObj,
    sourceObj,
    keysInBothAcc,
    keysInTargetAcc,
  ) => {
    Object.entries(targetObj).forEach(([key, valueTargetObjEntry]) => {
      const valueSourceObjEntry = sourceObj[key];

      if (valueSourceObjEntry !== undefined) {
        if (isObject(valueTargetObjEntry) && isObject(valueSourceObjEntry)) {
          const targetSubObj = {};
          const sourceSubObj = {};
          findCommonKeys(
            valueTargetObjEntry,
            valueSourceObjEntry,
            targetSubObj,
            sourceSubObj,
          );

          if (Object.keys(targetSubObj).length > 0) {
            keysInBothAcc[key] = targetSubObj;
          }
          if (Object.keys(sourceSubObj).length > 0) {
            keysInTargetAcc[key] = sourceSubObj;
          }
        } else if (typeof valueTargetObjEntry === typeof valueSourceObjEntry) {
          keysInBothAcc[key] = valueTargetObjEntry;
        } else {
          keysInTargetAcc[key] = valueTargetObjEntry;
        }
      } else {
        keysInTargetAcc[key] = valueTargetObjEntry;
      }
    });
  };

  findCommonKeys(target, source, keysInTargetAndSource, keysOnlyInTarget);

  return { keysInTargetAndSource, keysOnlyInTarget };
};
