import { andesThemePrefix } from '../constants';
import { toVarsMap } from '../utils/cssVarsUtils';
import {
  separateComponentStylesFromComponentEntries,
  separateCssStylesFromCustomVars,
} from '../components/ThemeBuilder/ThemeBuilderUtils';
import { diffDeep } from '../utils/utils';
import mlTheme from '../../meli-themes/ml.json';
import { senderMetrics, trackCustomization } from '@andes/common/build/metrics';

/** @param {Object} [obj] */
const hasProperties = (obj) => (
  obj && typeof obj === 'object' && Object.keys(obj).length > 0
);

/**
 * @param {import('../..').AndesProviderTheme} theme
 * */
export const registerMetric = (theme = {}) => {
  if (typeof window !== 'undefined') return;

  const metrics = senderMetrics?.(trackCustomization);

  const { core = {}, colorSchemes = {}, components = {} } = theme;
  let allTokens = /** @type {Record<string, string>} */ ({});

  if (hasProperties(core)) {
    const { keysInTargetAndSource: coreVars } = diffDeep(core, mlTheme.core || {});
    allTokens = { ...allTokens, ...toVarsMap(coreVars, andesThemePrefix) };
  }

  if (hasProperties(colorSchemes)) {
    const { light = {} } = colorSchemes;

    if (hasProperties(light)) {
      const { keysInTargetAndSource: semanticVars } = diffDeep(light, mlTheme.colorSchemes.light || {});
      allTokens = { ...allTokens, ...toVarsMap(semanticVars, andesThemePrefix) };
    }
  }

  if (hasProperties(components)) {
    Object.entries(components).forEach(([component, value = {}]) => {
      const { componentStyles, componentOverrides } = separateComponentStylesFromComponentEntries(value);
      const { keysInTargetAndSource: componentVars, keysOnlyInTarget: customStyles } = diffDeep(
        componentStyles,
        mlTheme.components[/** @type {keyof typeof mlTheme.components} */ (component)] || {},
      );
      const { cssStyles } = separateCssStylesFromCustomVars(customStyles);

      allTokens = {
        ...allTokens,
        ...toVarsMap({ [component]: componentVars }, andesThemePrefix),
      };

      if (hasProperties(componentOverrides?.styleOverrides)) {
        metrics?.sendStyleOverrides?.({ component });
      }

      if (hasProperties(cssStyles)) {
        metrics?.sendCustom?.({ component, details: cssStyles });
      }
    });
  }

  if (hasProperties(allTokens)) {
    metrics?.sendTokens?.({ details: allTokens });
  }
};
